import{_ as i,o as l,c as s,a2 as e}from"./chunks/framework.BflysNKA.js";const u=JSON.parse('{"title":"Hapi 优选 IP 配置","description":"","frontmatter":{},"headers":[],"relativePath":"apps/hapi-ip.md","filePath":"apps/hapi-ip.md","lastUpdated":1778577020000}'),p={name:"apps/hapi-ip.md"};function n(r,a,t,o,h,d){return l(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="hapi-优选-ip-配置" tabindex="-1">Hapi 优选 IP 配置 <a class="header-anchor" href="#hapi-优选-ip-配置" aria-label="Permalink to &quot;Hapi 优选 IP 配置&quot;">​</a></h1><p>大多数情况下，HAPI 保持默认网络就能正常使用。只有在远程入口已经跑通，但不同地区访问差异明显、手机接管不稳定、或者你准备长期在线使用时，再继续看这一页。</p><p>如果你还没完成基础接入，先看 <a href="/apps/hapi">Hapi 远程控制</a>。<br> 如果你已经能正常远程接入，只是想继续优化访问体验，再看 <a href="/apps/hapi-advanced">Hapi 进阶：优选 IP 配置</a>。</p><h2 id="先判断是不是-ip-问题" tabindex="-1">先判断是不是 IP 问题 <a class="header-anchor" href="#先判断是不是-ip-问题" aria-label="Permalink to &quot;先判断是不是 IP 问题&quot;">​</a></h2><p>很多人看到“远程体验差”，会直接把问题归到 IP 或线路上。实际上，HAPI 常见问题通常先分成两层：</p><ol><li><strong>HAPI 远程入口层</strong> 决定手机或浏览器能不能顺利打开会话页面</li><li><strong>底层模型调用层</strong> 决定 Claude Code、Codex、OpenCode 自己连到 小蓝中转站 后快不快</li></ol><p>可以这样判断：</p><ul><li><strong>页面都很难打开</strong>：先看 HAPI Hub、Relay、当前网络</li><li><strong>页面打开正常，但消息发不出去</strong>：先看会话状态和 Runner</li><li><strong>页面与消息都正常，只是回复慢</strong>：优先回到底层 CLI、模型和上下文大小</li></ul><p>也就是说，“优选 IP”主要是在优化第一层，不是替代模型配置。</p><p>如果你只想先判断自己该走哪条路线，可以先按使用场景分：</p><ul><li><strong>同一 Wi-Fi 下临时接管</strong>：优先局域网直连</li><li><strong>自己几台设备长期互通</strong>：优先固定设备网络互联</li><li><strong>给外部浏览器长期访问</strong>：优先固定公网入口或稳定隧道</li></ul><p>场景先选对，后面才谈得上“优选”。</p><h2 id="什么情况下值得继续优化" tabindex="-1">什么情况下值得继续优化 <a class="header-anchor" href="#什么情况下值得继续优化" aria-label="Permalink to &quot;什么情况下值得继续优化&quot;">​</a></h2><p>出现下面这些情况时，再继续折腾入口线路更有意义：</p><ul><li>同一条会话，本机访问正常，手机外网访问不稳定</li><li>不同地区同事接入同一个 HAPI Hub，体验差异明显</li><li>HAPI 准备长期跑在远端开发机、云主机或家里常开电脑上</li><li>你已经把 Claude Code、Codex 或 OpenCode 单独跑通，只剩远程体验还不够稳</li></ul><p>如果只是偶尔临时接管一次，默认链路通常已经够用。</p><h2 id="更稳的做法" tabindex="-1">更稳的做法 <a class="header-anchor" href="#更稳的做法" aria-label="Permalink to &quot;更稳的做法&quot;">​</a></h2><h3 id="先固定一台稳定机器" tabindex="-1">先固定一台稳定机器 <a class="header-anchor" href="#先固定一台稳定机器" aria-label="Permalink to &quot;先固定一台稳定机器&quot;">​</a></h3><p>比起在笔记本上临时开一条会话，固定一台更少休眠、少切网的机器会稳很多。</p><p>适合长期使用的机器通常有这些特点：</p><ul><li>不会频繁合盖睡眠</li><li>网络出口比较固定</li><li>项目目录和 CLI 配置长期保留</li></ul><p>这样做的好处是，HAPI 入口、底层 CLI、工作目录都会更稳定，不需要每次出门前重新搭一遍。</p><h3 id="先让最短链路跑通" tabindex="-1">先让最短链路跑通 <a class="header-anchor" href="#先让最短链路跑通" aria-label="Permalink to &quot;先让最短链路跑通&quot;">​</a></h3><p>优选 IP 不是一开始就加很多中间层。更稳的顺序是：</p><ol><li>本机浏览器访问 HAPI</li><li>同一网络下另一台设备访问 HAPI</li><li>手机流量或外网访问 HAPI</li><li>确认长期需求后，再考虑固定入口、反代或其他网络优化</li></ol><p>链路越短，定位问题越快。先把最短路径跑通，再去做更复杂的入口设计。</p><p>同局域网访问时，最容易忽略的一步是监听地址。<br> 如果 Hub 还只监听 <code>127.0.0.1</code>，那本机能打开并不代表同网设备也能打开。</p><h3 id="先证明底层-cli-已经稳定" tabindex="-1">先证明底层 CLI 已经稳定 <a class="header-anchor" href="#先证明底层-cli-已经稳定" aria-label="Permalink to &quot;先证明底层 CLI 已经稳定&quot;">​</a></h3><p>继续优化前，最好先单独验证一次底层工具：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">gemini</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">opencode</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>以及至少跑通一条真实会话。原因很简单：如果底层 CLI 自己都还没稳定走 小蓝中转站，继续换入口线路也不会让会话变正常。</p><h2 id="一个实用的排查顺序" tabindex="-1">一个实用的排查顺序 <a class="header-anchor" href="#一个实用的排查顺序" aria-label="Permalink to &quot;一个实用的排查顺序&quot;">​</a></h2><p>怀疑远程体验差时，按这个顺序看最省时间：</p><ol><li>先在本机单独运行底层 CLI，确认模型回复正常</li><li>再确认 <code>hapi hub</code> 或 <code>hapi hub --relay</code> 能稳定给出访问入口</li><li>用本机浏览器接一次</li><li>用同局域网设备再接一次</li><li>最后再换外网、热点或长期在线机器</li></ol><p>只有前面几步都已经稳定，后面的线路优化才是“提速”；否则很容易把基础配置错误误判成 IP 问题。</p>`,35)])])}const C=i(p,[["render",n]]);export{u as __pageData,C as default};
